/**
 * slidingWindowRateLimiter.js
 *
 * TRUE sliding window rate-limiting middleware for Express.js.
 *
 * Unlike a fixed-window limiter (which resets a counter at regular clock
 * intervals), this implementation records the timestamp of every individual
 * request and, on each incoming request, discards timestamps older than
 * `windowMs`.  The live count is always computed over the last `windowMs`
 * milliseconds relative to "right now", giving a perfectly smooth sliding
 * window with no cliff-edge burst at window boundaries.
 *
 * ─── PROXY NOTE ────────────────────────────────────────────────────────────
 * Client identification uses `req.ip`, which Express resolves from the
 * X-Forwarded-For header ONLY when the `trust proxy` application setting is
 * enabled.  Without it, `req.ip` is always the direct socket address (your
 * reverse proxy's IP), causing ALL traffic to share a single rate-limit bucket.
 *
 *   // Enable for a single trusted proxy hop (e.g. Nginx on the same host):
 *   app.set('trust proxy', 1);
 *
 *   // Enable for N hops, a CIDR range, or specific IPs — see Express docs:
 *   // https://expressjs.com/en/guide/behind-proxies.html
 * ───────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window size in milliseconds.
 * @property {number} [maxRequests=100]  - Maximum requests allowed per window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {function} middleware - Express middleware `(req, res, next) => void`.
 * @property {function} close      - Stops the background cleanup interval so the
 *                                   process can exit cleanly.  Call on shutdown.
 */

/**
 * Creates a sliding-window rate-limiter.
 *
 * @param {RateLimiterOptions} [options={}]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = (typeof options.windowMs    === 'number' && options.windowMs    > 0)
                        ? options.windowMs    : 60_000;
  const maxRequests = (typeof options.maxRequests === 'number' && options.maxRequests > 0)
                        ? options.maxRequests : 100;

  /**
   * Per-IP timestamp store.
   *
   * Map<string, number[]>  —  IP → request timestamps in milliseconds,
   * kept in ascending (oldest-first) order so the prune step is O(k).
   */
  const store = new Map();

  // ── Sliding-window core ───────────────────────────────────────────────────

  /**
   * Removes timestamps older than `windowMs` from the front of the array.
   * Timestamps are always appended at the back, so the array stays sorted
   * and we only ever need to trim the leading prefix.
   *
   * @param {number[]} timestamps - Mutable, ascending array of epoch-ms values.
   * @param {number}   now        - Current epoch time in milliseconds.
   */
  function pruneExpired(timestamps, now) {
    const cutoff = now - windowMs;
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    if (i > 0) timestamps.splice(0, i);
  }

  // ── Background cleanup ────────────────────────────────────────────────────

  /**
   * Every 60 s, sweep the store and delete entries for IPs whose entire
   * timestamp log has aged out of the window.  Prevents unbounded memory
   * growth from long-tail IPs that sent a burst and then went silent.
   */
  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    for (const [ip, timestamps] of store) {
      pruneExpired(timestamps, now);
      if (timestamps.length === 0) store.delete(ip);
    }
  }, 60_000);

  // `unref()` means this timer alone won't keep the Node process alive —
  // belt-and-suspenders alongside the explicit `close()` below.
  if (cleanupInterval.unref) cleanupInterval.unref();

  // ── Middleware ────────────────────────────────────────────────────────────

  /**
   * Express middleware: sliding-window check per client IP.
   *
   * @param {import('express').Request}      req
   * @param {import('express').Response}     res
   * @param {import('express').NextFunction} next
   */
  function middleware(req, res, next) {
    // Falls back to the raw socket address; see PROXY NOTE above.
    const ip  = req.ip || req.socket.remoteAddress || 'unknown';
    const now = Date.now();

    // Retrieve or initialise the timestamp log for this IP.
    let timestamps = store.get(ip);
    if (!timestamps) {
      timestamps = [];
      store.set(ip, timestamps);
    }

    // ── Step 1: slide the window ──────────────────────────────────────────
    // Remove all timestamps outside [now - windowMs, now].
    pruneExpired(timestamps, now);

    const currentCount = timestamps.length;

    // ── Step 2a: REJECTED — limit already reached ─────────────────────────
    if (currentCount >= maxRequests) {
      // The client must wait until the oldest surviving timestamp ages out.
      const retryAfterMs  = (timestamps[0] + windowMs) - now;
      const retryAfterSec = Math.ceil(retryAfterMs / 1000);

      res.set('Retry-After', String(retryAfterSec));
      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // ── Step 2b: ALLOWED — record request, set informational headers ───────
    timestamps.push(now); // always appended → array stays sorted

    // Reset = the moment the oldest slot in the window expires, freeing +1.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(maxRequests - timestamps.length),
      'X-RateLimit-Reset':     String(resetEpochSec),
    });

    next();
  }

  // ── Lifecycle ─────────────────────────────────────────────────────────────

  /**
   * Stops the background cleanup interval.
   * Call this during graceful shutdown to allow the process to exit cleanly.
   */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
