const authLimiter = createRateLimiter({ windowMs: 60_000, maxRequests: 10 });
app.post('/login',   authLimiter.middleware, (req, res) => res.json({ ok: true }));
app.post('/refresh', authLimiter.middleware, (req, res) => res.json({ ok: true }));

